<template>
    <section>
        <div class="my-popups">
            <loader :is-visible="isLoading"></loader>
            <div class="modal d-block">
                <div class="modal-dialog modal-dialog-centered">
                    <div class="modal-content">
                        <div class="modal-header theme-primary partition-full d-flex">
                            <h4 class="modal-title">{{ $t('Edit') }} {{ $t(NewTabName) }}</h4>
                            <button type="button" class="close" @click="Cancel">
                                <em class="fa fa-times" aria-hidden="true"></em>
                            </button>
                        </div>
                        <div class="modal-body">
                            <dynamic-form ref="dynamicform" lang="en" :mandatorytext="$t('MandatoryString')" :buttons="buttons" :schema="FormSchema" v-on:OnSubmit="UpdateTeamMember">
                             
                            </dynamic-form>
                        </div>
                    </div>
                </div>
            </div>
        </div>

    </section>
</template>
<script>
import { type } from 'jquery';
import DataService from '../../services/DataService';

import AddExpense from './AddExpense.vue';
export default {
    components: { AddExpense },
    props: {

        ProjectName: {
            type: String,
            required: true
        },
        EditData:{
            type:Object,
            require:false
        },
        NewTabName:{
            type:String,
            require: true
        },
        TabsArray:{
            type:Array
        }

    },
    data() {
        return {
            noRecord: false,
            TotalRecords: 0,
            isLoading: false,
            taskOptions: [],
            progress: 0,
            projectId: '',
            userId: '',
            companyId: '',
            startDate: '',
            dueDate: '',
            AddExpense: false,
            FormSchema: [
                {
                    layoutType: "double",
                    Data: [
                        {
                            astype: "TextField",
                            label: this.$t('Member Name'),
                            name: "MemberName",
                            disabled:true,
                            value: "",
                            placeholder: "",
                            validationRules: {
                                "required": true,
                                "regex": /^[a-zA-Z0-9\s]*$/
                            },
                            disabled: false,
                        },
                        {
                            astype: "TextField",
                            label: this.$t('AliasName'),
                            name: "AliasName",
                            value: "",
                            placeholder: "",
                            validationRules: {
                                "required": true,
                                "regex": /^[a-zA-Z0-9\s]*$/
                            },
                            disabled: false,
                        },
                        {
                            astype: "TextField",
                            label: this.$t('Department'),
                            name: "Department",
                            value: "",
                            placeholder: "",
                            validationRules: {
                                "required": true,
                                "regex": /^[a-zA-Z0-9\s]*$/
                            },
                            disabled: true,
                        },
                        {
                            astype: "SelectField",
                            label: this.$t('Designation'),
                            name: "Designation",
                            value: "",
                            placeholder: "",
                            config: {
                                options: []
                            },
                            validationRules: {
                                "required": true,
                                "regex": /^[a-zA-Z0-9\s]*$/
                            },
                            disabled: false,

                        },
                        {
                            astype: "NumericField",
                            label: this.$t('Rate'),
                            name: "rate",
                            value: "",
                            placeholder: "Enter Rate",
                            validationRules: {
                                "required": true,
                                "regex": /^[a-zA-Z0-9\s]*$/,
                                 "max": 5
                            },
                            disabled: false,
                        },
                        {
                            astype: "CheckBoxField",
                            label: this.$t('Default PM'),
                            name: "DefaultPM",
                            value: "",
                            placeholder: "",
                            config: {
                                options: [{ name: "", value: "true" }],
                                showAddIcon: false,
                                onChange: this.GetCheckBoxValue

                            },
                            validationRules: "",
                        },

                        {
                            astype: "CheckBoxField",
                            label: this.$t('Show Alias Name'),
                            name: "ShowAliasName",
                            value: "",
                            placeholder: "",
                            config: {
                                options: [{ name: "", value: "true" }],
                                showAddIcon: false,
                                onChange: this.GetCheckBoxValue

                            },
                            validationRules: "",
                        },
                    ]
                },


            ],
            buttons: [
                {
                    type: "submit",
                    class: "btn btn-success",
                    text: "<i class='fa fa-save pr-2'></i>Save",
                    isVisible: true
                },
                {
                    type: "button",
                    class: "btn btn-danger",
                    text: "<i class='fa fa-close pr-2'></i>Cancel",
                    onClick: this.Cancel,
                },
            ],
            DesignationData: [],         
            MemberDetail:{},
            UserId:0,
           Currency:''
        }
    },
   async created() {

        var vm = this;
        vm.FormSchema[0].Data[0].label=`${vm.$t(vm.TabsArray[1])} ${vm.$t('MemberName')}`;
        vm.projectId = vm.$route.params.projectId;
       await vm.GetDesignationDetails();
        vm.BindUserDetails(vm.EditData);
        vm.Currency=vm.GetUserInfo.Currency.replace(/[()]/g, '');
        vm.FormSchema[0].Data[4].label= vm.$t('Rate') + '('+vm.Currency +')';
        // vm.GetMemebrDetails();

    },
    methods: {
         BindUserDetails(data){            
            var vm=this;
            vm.UserId=data.USER_ID;
            vm.FormSchema[0].Data[0].value= data.USER_NAME;
            vm.FormSchema[0].Data[1].value= data.ALIASNAME;
            vm.FormSchema[0].Data[2].value= data.DEPARTMENT;
            vm.FormSchema[0].Data[4].value= data.RATE;
            vm.DesignationData.forEach((itme)=>{
                if(itme.designation_name=== data.DESIGNATION_NAME)
                    {
                        vm.FormSchema[0].Data[3].value=itme.designation_id;
                    }
                    });                    
                    vm.FormSchema[0].Data[5].value = data.USER_TYPE_ID==2 ? ["true"] : [];
                    vm.FormSchema[0].Data[6].value = data.SHOWALIAS ? ["true"] : [];
         },
        Cancel() {
            this.$parent.IsEditTeamShow = false;
        },
        GetDesignationDetails:async function () {
            var ths = this;
          await  DataService.GetDesignationDetails().then((response) => {
                if (response.data[0].Status == 'Success') {

                    var Data = response.data[0].Result;

                    ths.DesignationData = JSON.parse(Data).ListData;

                    ths.DesignationData.forEach((element) => {
                        var obj = {
                            value: element.designation_id,
                            name: element.designation_name
                        }
                        ths.FormSchema[0].Data[3].config.options.push(obj);                        
                    })
                    ths.$refs.dynamicform.UpdateKeyValue();

                }
            })
        },
        UpdateTeamMember: function () {            
            var vm = this;
            var AliasName = vm.FormSchema[0].Data[1].value;
            var DesignationId = vm.FormSchema[0].Data[3].value;
            var Rate = vm.FormSchema[0].Data[4].value;
            var DefaultPm = vm.FormSchema[0].Data[5].value;
             var DefaultPmValue=DefaultPm.length > 0 ?true: false;
            var ShowAlias = vm.FormSchema[0].Data[6].value;      
             var ShowAliasvalue= ShowAlias.length > 0 ? true:false;      
             var PUserId = vm.UserId;
            var ProjectId = vm.projectId;
            var url = `DesignationId=${DesignationId}&AliasName=${AliasName}&ShowAlias=${ShowAliasvalue}&DefaultPm=${DefaultPmValue}&PUserId=${PUserId}&ProjectId=${ProjectId}&Rate=${Rate}`;
            DataService.UpdateMemebrDetails(url).then((response) => {
                if (response.data[0].Status == 'Success') {                    
                    vm.ShowAlert(vm.$t('UpdatedSuccess',[vm.$t(vm.NewTabName)]), "success", true,  vm.$t("Alert"));
                    vm.$parent.IsEditTeamShow = false;
                    vm.$parent.refreshTeamList();
                }
                else{
                    
                    vm.ShowAlert(vm.$t("Error"), "failure",vm.$t('Alert'));
                   
                   
                }
            })
            
        }
    }

};

</script>

